const path = require('path');
const fs = require('fs');

function readLogFile(filename) {
    if (!filename || typeof filename !== 'string') {
        throw new Error('Invalid filename provided');
    }

    const LOG_DIRECTORY = path.resolve('/var/log/app');

    const sanitizedFilename = path.basename(filename);

    if (!sanitizedFilename.endsWith('.log')) {
        throw new Error('Only .log files are allowed');
    }

    const allowedPattern = /^[a-zA-Z0-9_\-]+\.log$/;
    if (!allowedPattern.test(sanitizedFilename)) {
        throw new Error('Filename contains invalid characters');
    }

    const filePath = path.join(LOG_DIRECTORY, sanitizedFilename);

    const resolvedPath = path.resolve(filePath);
    if (!resolvedPath.startsWith(LOG_DIRECTORY + path.sep)) {
        throw new Error('Access denied: path traversal detected');
    }

    if (!fs.existsSync(resolvedPath)) {
        throw new Error('Log file not found');
    }

    const stats = fs.statSync(resolvedPath);
    if (!stats.isFile()) {
        throw new Error('Path is not a regular file');
    }

    const MAX_FILE_SIZE = 10 * 1024 * 1024; // 10 MB
    if (stats.size > MAX_FILE_SIZE) {
        throw new Error('File exceeds maximum allowed size');
    }

    const contents = fs.readFileSync(resolvedPath, 'utf8');
    return contents;
}

